/** Auto-generated from public/index.html — run: node scripts/embed.js */
module.exports = "<!DOCTYPE html>\n<html lang=\"ja\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>QR Magic（個人用）</title>\n  <style>\n    :root { font-family: system-ui, sans-serif; color: #111; background: #f4f4f5; }\n    body { margin: 0 auto; max-width: 520px; padding: 1rem 1rem 3rem; }\n    h1 { font-size: 1.15rem; margin: 0 0 0.75rem; }\n    h2 { font-size: 0.95rem; margin: 1.25rem 0 0.5rem; }\n    input[type=\"text\"], input[type=\"password\"], textarea {\n      width: 100%; box-sizing: border-box; padding: 0.5rem; font-size: 1rem; border: 1px solid #ccc; border-radius: 6px;\n    }\n    textarea { min-height: 2.5rem; resize: vertical; }\n    button {\n      cursor: pointer; border: none; border-radius: 8px; padding: 0.65rem 1rem; font-size: 0.95rem; font-weight: 600;\n    }\n    .btn-primary { background: #2563eb; color: #fff; }\n    .btn-secondary { background: #e4e4e7; color: #18181b; }\n    .btn-danger { background: #dc2626; color: #fff; }\n    .panel { background: #fff; border-radius: 10px; padding: 0.85rem; border: 1px solid #e4e4e7; margin-top: 0.75rem; }\n    .muted { color: #71717a; font-size: 0.85rem; word-break: break-all; }\n    .toolbar { display: flex; flex-wrap: wrap; gap: 0.5rem; margin-top: 0.5rem; }\n  </style>\n</head>\n<body>\n  <h1>QR Magic（個人用）</h1>\n  <p class=\"muted\">アカウントはありません。<code>ADMIN_TOKEN</code> を知っている人だけが設定できます。</p>\n\n  <div id=\"gate\" class=\"panel\">\n    <h2>管理用トークン</h2>\n    <p class=\"muted\">サーバーの環境変数 <code>ADMIN_TOKEN</code> と同じ文字列を入力してください。</p>\n    <input type=\"password\" id=\"gateToken\" placeholder=\"ADMIN_TOKEN\" autocomplete=\"off\" />\n    <div class=\"toolbar\" style=\"margin-top:0.65rem\">\n      <button type=\"button\" class=\"btn-primary\" id=\"gateBtn\">開く</button>\n    </div>\n  </div>\n\n  <div id=\"app\" style=\"display:none\">\n    <div class=\"panel\">\n      <h2>リダイレクトURLのテンプレート</h2>\n      <p class=\"muted\">必ず <code>{query}</code> を含めてください。任意で <code>{host}</code>。</p>\n      <textarea id=\"template\"></textarea>\n    </div>\n\n    <div class=\"panel\">\n      <h2>キーワード</h2>\n      <p class=\"muted\">名刺用QRの<strong>初回</strong>に使う単語です。本番で入れ替えてから <strong>設定を保存</strong>し、観客に読ませてください。</p>\n      <input type=\"text\" id=\"keyword\" placeholder=\"例: りんご\" autocomplete=\"off\" />\n      <div class=\"toolbar\">\n        <button type=\"button\" class=\"btn-secondary\" id=\"btnPreviewKeyword\">プレビュー</button>\n        <button type=\"button\" class=\"btn-primary\" id=\"saveBtn\">設定を保存</button>\n      </div>\n    </div>\n\n    <div class=\"panel\">\n      <h2>現在の状態</h2>\n      <p id=\"statusLine\" class=\"muted\"></p>\n    </div>\n\n    <div class=\"panel\">\n      <h2>名刺用QR（1枚＝1URL・初回で単語固定）</h2>\n      <p class=\"muted\">先に<strong>URLだけ</strong>をたくさん作り、名刺に<strong>それぞれ違うQR</strong>を印刷しておきます。</p>\n      <p class=\"muted\">本番で上のキーワードを入れて保存したうえで、観客がその名刺のQRを<strong>初めて</strong>読むと、その単語に<strong>ずっと</strong>固定されます。名刺ごとに別の単語にしたいときは、読ませるタイミングでキーワードを変えてください。</p>\n      <p class=\"muted\">飛び先は「リダイレクトURLのテンプレート」を使います。1回あたり最大5000枚。</p>\n      <p id=\"ticketStatus\" class=\"muted\"></p>\n      <label class=\"muted\">枚数</label>\n      <input type=\"number\" id=\"ticketCount\" value=\"10\" min=\"1\" max=\"5000\" style=\"width:6rem;margin-left:.35rem\" />\n      <div class=\"toolbar\" style=\"margin-top:0.5rem\">\n        <button type=\"button\" class=\"btn-primary\" id=\"btnIssueTickets\">名刺用URLを発行</button>\n        <button type=\"button\" class=\"btn-danger\" id=\"btnClearTickets\">名刺用を全削除</button>\n      </div>\n      <label class=\"muted\" style=\"display:block;margin-top:0.65rem\">発行されたURL（1行1本・QRにしてください）</label>\n      <textarea id=\"ticketUrls\" readonly rows=\"10\" style=\"width:100%;font-size:.72rem;font-family:ui-monospace,monospace\"></textarea>\n    </div>\n  </div>\n\n  <p id=\"toast\" style=\"display:none;position:fixed;bottom:1rem;left:50%;transform:translateX(-50%);background:#111;color:#fff;padding:.6rem 1rem;border-radius:8px;z-index:100\"></p>\n\n  <script>\n    const LS = \"qr_magic_admin_token\";\n    const gate = document.getElementById(\"gate\");\n    const appEl = document.getElementById(\"app\");\n\n    let adminToken = localStorage.getItem(LS) || \"\";\n    let state = null;\n    /** サーバー .env の PUBLIC_BASE_URL（https の観客用オリジン） */\n    let publicBaseUrl = \"\";\n\n    function toast(msg) {\n      const t = document.getElementById(\"toast\");\n      t.textContent = msg;\n      t.style.display = \"block\";\n      setTimeout(() => { t.style.display = \"none\"; }, 2200);\n    }\n\n    function authHeaders() {\n      return { Authorization: \"Bearer \" + adminToken, \"Content-Type\": \"application/json\" };\n    }\n\n    async function api(path, opt = {}) {\n      const r = await fetch(path, { ...opt, headers: { ...authHeaders(), ...opt.headers } });\n      if (r.status === 401) {\n        localStorage.removeItem(LS);\n        location.reload();\n        throw new Error(\"unauthorized\");\n      }\n      const j = await r.json().catch(() => ({}));\n      if (!r.ok) throw new Error(j.message || r.statusText);\n      return j;\n    }\n\n    function audienceOrigin() {\n      return (publicBaseUrl && publicBaseUrl.length > 0 ? publicBaseUrl : location.origin).replace(/\\/+$/, \"\");\n    }\n\n    function buildUrl(template, query) {\n      const host = audienceOrigin();\n      return template.replaceAll(\"{host}\", host).replaceAll(\"{query}\", encodeURIComponent(query));\n    }\n\n    function syncKeywordFromState() {\n      const q = (state.queries && state.queries[0]) || \"\";\n      document.getElementById(\"keyword\").value = q;\n    }\n\n    function renderAll() {\n      document.getElementById(\"template\").value = state.serviceTemplate || \"\";\n      document.getElementById(\"statusLine\").textContent =\n        \"キーワード: \" + ((state.queries && state.queries[0]) || \"（空）\") +\n        \" / 名刺用URL数: \" + (state.ticketCount != null ? state.ticketCount : 0);\n      document.getElementById(\"ticketStatus\").textContent =\n        \"登録中の名刺用URL: \" + (state.ticketCount != null ? state.ticketCount : 0) + \" 本\";\n      syncKeywordFromState();\n    }\n\n    async function load() {\n      const data = await api(\"/api/state\");\n      publicBaseUrl = typeof data.publicBaseUrl === \"string\" ? data.publicBaseUrl.trim() : \"\";\n      state = data.state;\n      renderAll();\n    }\n\n    async function save() {\n      state.serviceTemplate = document.getElementById(\"template\").value.trim();\n      if (!state.serviceTemplate.includes(\"{query}\")) {\n        toast(\"{query} を含めてください\");\n        return;\n      }\n      const kw = document.getElementById(\"keyword\").value.trim();\n      const data = await api(\"/api/state\", {\n        method: \"PUT\",\n        body: JSON.stringify({ queries: [kw], serviceTemplate: state.serviceTemplate }),\n      });\n      state = data.state;\n      toast(\"保存しました\");\n      renderAll();\n    }\n\n    document.getElementById(\"btnPreviewKeyword\").onclick = () => {\n      const tmpl = document.getElementById(\"template\").value.trim();\n      const kw = document.getElementById(\"keyword\").value.trim();\n      if (!tmpl.includes(\"{query}\")) return toast(\"{query} を含めてください\");\n      if (!kw) return toast(\"キーワードが空です\");\n      window.open(buildUrl(tmpl, kw), \"_blank\");\n    };\n\n    document.getElementById(\"gateBtn\").onclick = () => {\n      const v = document.getElementById(\"gateToken\").value.trim();\n      if (!v) return toast(\"トークンを入力してください\");\n      adminToken = v;\n      localStorage.setItem(LS, adminToken);\n      startApp();\n    };\n\n    document.getElementById(\"saveBtn\").onclick = () => save().catch((e) => toast(String(e.message || e)));\n\n    document.getElementById(\"btnIssueTickets\").onclick = () => {\n      const n = parseInt(document.getElementById(\"ticketCount\").value, 10);\n      if (!Number.isFinite(n) || n < 1 || n > 5000) return toast(\"枚数は1〜5000\");\n      api(\"/api/tickets/bulk\", { method: \"POST\", body: JSON.stringify({ count: n }) })\n        .then((d) => {\n          state.ticketCount = d.ticketCount;\n          const base = audienceOrigin();\n          const lines = (d.tickets || []).map((x) => base + x.path);\n          document.getElementById(\"ticketUrls\").value = lines.join(\"\\n\");\n          toast(\"発行しました\");\n          renderAll();\n        })\n        .catch((e) => toast(String(e.message || e)));\n    };\n    document.getElementById(\"btnClearTickets\").onclick = () => {\n      if (!confirm(\"名刺用URLをすべて削除します。よろしいですか？\")) return;\n      api(\"/api/tickets/clear\", { method: \"POST\", body: JSON.stringify({ confirm: true }) })\n        .then((d) => {\n          state.ticketCount = d.ticketCount;\n          document.getElementById(\"ticketUrls\").value = \"\";\n          toast(\"削除しました\");\n          renderAll();\n        })\n        .catch((e) => toast(String(e.message || e)));\n    };\n\n    let pollTimer = null;\n    function startPublicUrlPoller() {\n      if (pollTimer) return;\n      let n = 0;\n      pollTimer = setInterval(async () => {\n        n++;\n        if (n > 45) {\n          clearInterval(pollTimer);\n          pollTimer = null;\n        }\n        try {\n          const r = await fetch(\"/api/public-qr-hint\");\n          const d = await r.json();\n          const base = (d.publicBaseUrl || \"\").replace(/\\/+$/, \"\");\n          if (base && state) {\n            const changed = base !== publicBaseUrl;\n            publicBaseUrl = base;\n            if (changed) renderAll();\n          }\n        } catch (_) {}\n      }, 2000);\n    }\n\n    async function startApp() {\n      try {\n        await load();\n        gate.style.display = \"none\";\n        appEl.style.display = \"block\";\n        startPublicUrlPoller();\n      } catch (e) {\n        localStorage.removeItem(LS);\n        adminToken = \"\";\n        gate.style.display = \"block\";\n        appEl.style.display = \"none\";\n        toast(\"読み込み失敗: トークンを確認してください\");\n      }\n    }\n\n    if (adminToken) startApp();\n  </script>\n</body>\n</html>\n";
